package multidimensionais.arrays.praticando.aprendendo;public class ArraysMultidimensionais02 {    public static void main(String[] args) {        int[][] numeresArrays = new int[3][];        numeresArrays[0] = new int[3];        numeresArrays[1] = new int[5];        numeresArrays[2] = new int[7];        for (int[] num : numeresArrays){            System.out.print(" -------\n");            for (int numArrays : num){                System.out.print(numArrays);            }        }    }}